"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[6469],{26543:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-7260e2c4",path:"/css-tutorial/feature/counter.html",title:"CSS 计数器",lang:"zh-CN",frontmatter:{summary:"CSS 计数器 简介 counter-reset：新建或重置一个计数器。; counter-increment：指定计数器的值加1。; counter()：取出指定计数器的值。; 下面是一个例子。 counter-reset counter-reset属性新建或重置计数器。计数器的值默认为0。 可以使用第二个参数，修改计数器的默认值。 上面示例将计数器的默认",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/css-tutorial/feature/counter.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"CSS 计数器"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"简介",slug:"简介",children:[]},{level:2,title:"counter-reset",slug:"counter-reset",children:[]},{level:2,title:"counter-increment",slug:"counter-increment",children:[]},{level:2,title:"counter()",slug:"counter",children:[]},{level:2,title:"counters()",slug:"counters",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:2.32,words:695},filePathRelative:"css-tutorial/feature/counter.md"}},64937:(n,s,a)=>{a.r(s),a.d(s,{default:()=>p});const e=(0,a(66252).uE)('<h1 id="css-计数器" tabindex="-1"><a class="header-anchor" href="#css-计数器" aria-hidden="true">#</a> CSS 计数器</h1><h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><ul><li>counter-reset：新建或重置一个计数器。</li><li>counter-increment：指定计数器的值加1。</li><li>counter()：取出指定计数器的值。</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>counter-reset：counterName<span class="token punctuation">;</span>\n<span class="token property">counter-increment</span><span class="token punctuation">:</span> counterName<span class="token punctuation">;</span>\n<span class="token function">counter</span><span class="token punctuation">(</span>counterName<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>下面是一个例子。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">ul</span><span class="token punctuation">{</span>\n  <span class="token property">counter-reset</span><span class="token punctuation">:</span> section<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token selector">li</span><span class="token punctuation">{</span>\n  <span class="token property">list-style-type</span><span class="token punctuation">:</span> none<span class="token punctuation">;</span>\n  <span class="token property">counter-increment</span><span class="token punctuation">:</span> section<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token selector">li:before</span><span class="token punctuation">{</span>\n  <span class="token property">content</span><span class="token punctuation">:</span> <span class="token function">counters</span><span class="token punctuation">(</span>section<span class="token punctuation">,</span> <span class="token string">&#39;-&#39;</span><span class="token punctuation">)</span> <span class="token string">&#39;.&#39;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="counter-reset" tabindex="-1"><a class="header-anchor" href="#counter-reset" aria-hidden="true">#</a> counter-reset</h2><p><code>counter-reset</code>属性新建或重置计数器。计数器的值默认为<code>0</code>。</p><p>可以使用第二个参数，修改计数器的默认值。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">counter-reset</span><span class="token punctuation">:</span> count -1<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面示例将计数器的默认值设为<code>-1</code>。</p><p>可以在一条语句里面，同时新建多个计数器。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">counter-reset</span><span class="token punctuation">:</span> counter1 1 counter2 4<span class="token punctuation">;</span>\n<span class="token property">counter-reset</span><span class="token punctuation">:</span> chapter section 1 page<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>上面示例，第一行新建了两个计数器，第二行新建了三个计数器，并且计数器<code>section</code>的默认值设为<code>1</code>。</p><p>如果这个属性的值设为<code>none</code>，则表示不重置计数器，可以用来取消上层规则的设置。</p><h2 id="counter-increment" tabindex="-1"><a class="header-anchor" href="#counter-increment" aria-hidden="true">#</a> counter-increment</h2><p><code>counter-increment</code>属性默认将计数器的值加<code>1</code>，但也可以使用第二个值，指定变化的幅度。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">counter-increment</span><span class="token punctuation">:</span> counter-name -1<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面示例表示将计数器的值减<code>1</code>。</p><p>可以在一条<code>counter-increment</code>语句里面，同时改变多个计数器。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token property">counter-increment</span><span class="token punctuation">:</span> counter1 1 counter2 -4<span class="token punctuation">;</span>\n\n<span class="token property">counter-increment</span><span class="token punctuation">:</span> chapter section 2 page<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>上面示例的第一行，计数器<code>counter1</code>增加<code>1</code>，计数器<code>counter2</code>减去<code>4</code>。第二行，计数器<code>chapter</code>和<code>page</code>增加<code>1</code>，计数器<code>section</code>增加2。</p><p>如果这个属性设为<code>none</code>，表示不改变计数器的值。</p><h2 id="counter" tabindex="-1"><a class="header-anchor" href="#counter" aria-hidden="true">#</a> counter()</h2><p><code>counter()</code>还有可选的第二个参数，设置计数器的值样式，默认是阿拉伯数字。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token function">counter</span><span class="token punctuation">(</span>countername<span class="token punctuation">,</span> upper-roman<span class="token punctuation">)</span>；\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面示例将计数器的值样式设为大写的罗马数字。</p><p>常用的样式值如下。</p><ul><li>decimal-leading-zero：数字带有前导0。</li><li>lower-roman：小写的罗马数字。</li><li>upper-roman：大写的罗马数字。</li><li>lower-alpha：小写的英文字母。</li><li>upper-alpha：大写的英文字母。</li></ul><p>也可以使用<code>@counter-style</code>定义自己的规则。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@counter-style</span> winners-list</span> <span class="token punctuation">{</span>\n  <span class="token property">system</span><span class="token punctuation">:</span> fixed<span class="token punctuation">;</span>\n  <span class="token property">symbols</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span>gold-medal.svg<span class="token punctuation">)</span></span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span>silver-medal.svg<span class="token punctuation">)</span></span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span>bronze-medal.svg<span class="token punctuation">)</span></span><span class="token punctuation">;</span>\n  <span class="token property">suffix</span><span class="token punctuation">:</span> <span class="token string">&quot; &quot;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>上面示例是金牌、银牌、铜牌的计数符号。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@counter-style</span> thumbs</span> <span class="token punctuation">{</span>\n  <span class="token property">system</span><span class="token punctuation">:</span> cyclic<span class="token punctuation">;</span>\n  <span class="token property">symbols</span><span class="token punctuation">:</span> <span class="token string">&quot;\\1F44D&quot;</span><span class="token punctuation">;</span>\n  <span class="token property">suffix</span><span class="token punctuation">:</span> <span class="token string">&quot; &quot;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token selector">ul</span> <span class="token punctuation">{</span>\n  <span class="token property">list-style</span><span class="token punctuation">:</span> thumbs<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>上面示例是将列表符号变成点赞。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@counter-style</span> circled-alpha</span> <span class="token punctuation">{</span>\n  <span class="token property">system</span><span class="token punctuation">:</span> fixed<span class="token punctuation">;</span>\n  <span class="token property">symbols</span><span class="token punctuation">:</span> Ⓐ Ⓑ Ⓒ Ⓓ Ⓔ Ⓕ Ⓖ Ⓗ Ⓘ Ⓙ Ⓚ Ⓛ Ⓜ Ⓝ Ⓞ Ⓟ Ⓠ Ⓡ Ⓢ Ⓣ Ⓤ Ⓥ Ⓦ Ⓧ Ⓨ Ⓩ<span class="token punctuation">;</span>\n  <span class="token property">suffix</span><span class="token punctuation">:</span> <span class="token string">&quot; &quot;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token selector">.items</span> <span class="token punctuation">{</span>\n  <span class="token property">list-style</span><span class="token punctuation">:</span> circled-alpha<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>上面示例将列表符号变成带圈的英文字母。</p><h2 id="counters" tabindex="-1"><a class="header-anchor" href="#counters" aria-hidden="true">#</a> counters()</h2><p><code>counters()</code>用来取出计数器的值，并且指定多重计数器之间的连接字符。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token function">counters</span><span class="token punctuation">(</span>name<span class="token punctuation">,</span> strings<span class="token punctuation">,</span> style<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它与<code>counter()</code>的不同是多了一个<code>strings</code>参数，表示子序号的连接字符串。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token function">counters</span><span class="token punctuation">(</span>countername<span class="token punctuation">,</span> <span class="token string">&#39;-&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token function">counters</span><span class="token punctuation">(</span>countername<span class="token punctuation">,</span> <span class="token string">&#39;.&#39;</span><span class="token punctuation">,</span> upper-roman<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>上面示例第一行中，计数器与子计数器的连接符号为<code>-</code>。第二行为小数点。</p>',42),t={},p=(0,a(83744).Z)(t,[["render",function(n,s){return e}]])},83744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);